#include<cstdio>
#include<vector>
#include<algorithm>
#include<cstring>
#define SIZ(v) (int(v.size()))
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
typedef long long LL;
#define int LL
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}

const int N=2010,W=2000,Mod=998244353,PN=303;int a[N],P[N],dp[1<<13][PN],tot[1<<13],loc[N];
inline int qpow(int a,int b){int r(1);while(b)b&1?r=1ll*r*a%Mod:0,a=1ll*a*a%Mod,b=b>>1;return r;}
inline void DN(int &x){x>=Mod?x-=Mod:0;}inline void UP(int &x){x<0?x+=Mod:0;}
bool isp[N];int pm[PN],p;std::vector<int> PM[N]; int q[N];
inline void Init()
{
	memset(isp,1,sizeof(isp));isp[1]=false;rep(2,W,i){if(isp[i])pm[loc[i]=p++]=i;for(int j=i<<1;j<=W;j+=i)isp[j]=false;}
	rep(2,W,i){for(int j=0;j<p;++j)if(i%pm[j]==0){if(pm[j]<43)P[i]|=(1<<j);PM[i].push_back(j);}}
}
inline void Solve()
{
	int c=read(),T=0,ans=0;
	for(int i=0;i<c;++i){q[i]=read();if(q[i]<=43)T|=(1<<loc[q[i]]);} std::sort(q,q+c);
	for(int S=0;S<(1<<13);++S)if((S|T)==T)
	{
		int m=tot[S],res=1;
		for(int i=0;i<c;++i)if(q[i]>=43)
		{
			res=1ll*res*(qpow(2,dp[S][loc[q[i]]])-1)%Mod;
			m-=dp[S][loc[q[i]]];
		}
//		if(m<0)puts("QAQAQAQA");
//		printf("%d :: %d\n",S,m);
		res=1ll*res*qpow(2,m)%Mod;
		bool b=0;for(int i=0;i<13;++i)b^=((S>>i)&1);
		DN(ans+=(b?Mod-res:res));
	}
	printf("%lld\n",ans);return;
}
signed main()
{
//	FIN("card12.in");
	Init();int Q=read();while(Q--)++a[read()]; 
	for(int S=0;S<(1<<13);++S){rep(2,2000,i)if(!(P[i]&S))DN(dp[S][PM[i][SIZ(PM[i])-1]]+=a[i]),tot[S]+=a[i];tot[S]+=a[1];}
//	rep(8000,8191,S)printf("%d\n",tot[S]);return 0;
	Q=read();while(Q--)Solve();return 0;
}
